        dim_special = 0.4;
        dim_around = 0.55;
        shadow = {
          enabled = false;
        };
        blur = {
          enabled = true;
          size = 4;
          passes = 2;
          ignore_opacity = true;
        };
      };

      animations.enabled = true;
      bezier = [
        "quick,0.15,0,0.1,1"
        "easeOutQuint,0.23,1,0.32,1"
        "easeInOutCubic,0.65,0.05,0.36,1"
        "linear,0,0,1,1"
        "almostLinear,0.5,0.5,0.75,1.0"
      ];

      animation = [
        "windows,1,7,default,popin"
        "border,0"
        "fade,1,4,default"
        "workspaces,1,6,default,slide"
        "specialWorkspace,1,6,default,slidevert"
        "layers,0.5,6,default,fade"
      ];

      dwindle = {
        preserve_split = true;
      };

      misc = {
        focus_on_activate = true;
        force_default_wallpaper = 0;
        disable_hyprland_logo = true;
        disable_splash_rendering = true;
      };

      xwayland = {
        force_zero_scaling = true;
      };

      ecosystem = {
        no_update_news = true;
        no_donation_nag = true;
      };

      ### INPUT ###
      input = {
        kb_layout = "us";
        kb_options = "compose:caps";
        follow_mouse = 1;
        sensitivity = 0.8;
        touchpad.natural_scroll = false;
      };

      ### KEYBINDINGS ###
      "$mainMod" = "SUPER";

      binde = [
        ",XF86AudioRaiseVolume,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar volumeUp"
        ",XF86AudioLowerVolume,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar volumeDown"
        ",XF86MonBrightnessUp,exec,${pkgs.brightnessctl}/bin/brightnessctl set +5%; ${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar showBrightness"
        ",XF86MonBrightnessDown,exec,${pkgs.brightnessctl}/bin/brightnessctl set 5%-; ${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar showBrightness"
      ];

      bind = [
        ",XF86AudioPlay,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar mediaPlayPause"
        ",XF86AudioNext,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar mediaNext"
        ",XF86AudioPrev,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar mediaPrevious"
        ",XF86AudioMute,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar toggleAudioMute"
        ",PRINT,exec,hyprshot -m region -o ~/Pictures/Screenshots"
        "$mainMod,RETURN,exec,$terminal"
        "$mainMod,W,killactive"
        "$mainMod CONTROL,Q,exit"
        "$mainMod,P,exec,ghostty --class=dev.me.pi --title=Pi -e pi"
        "$mainMod,F,exec,$fileManager"
        "$mainMod SHIFT,F,exec,$fileManagergraphic"
        "$mainMod,N,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar toggleWifi"
        "$mainMod,B,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar toggleBluetooth"
        "$mainMod,U,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar toggleUpdates"
        "$mainMod,Q,exec,zeditor /home/ian/.config/nixos"
        "$mainMod SHIFT,Q,exec,$settings"
        "$mainMod,R,exec,$audio"
        "$mainMod,A,exec,$menu"
        "$mainMod,code:47,exec,${pkgs.quickshell}/bin/qs --config top-bar ipc call topbar toggleChromeTabs"
        "$mainMod,E,exec,$editor"
        "$mainMod,Z,layoutmsg,togglesplit"
        "$mainMod,G,exec,$browser"
        "$mainMod,X,exec,$calculator"
        "$mainMod,H,movefocus,l"
        "$mainMod,L,movefocus,r"
        "$mainMod,K,movefocus,u"
        "$mainMod,J,movefocus,d"
        "$mainMod SHIFT,H,movewindow,l"
        "$mainMod SHIFT,L,movewindow,r"
        "$mainMod SHIFT,K,movewindow,u"
        "$mainMod SHIFT,J,movewindow,d"
        "$mainMod,SPACE,fullscreen,1"
        "$mainMod SHIFT,SPACE,fullscreen,0"
        "$mainMod CONTROL,h,resizeactive,-50 0"
        "$mainMod CONTROL,j,resizeactive,0 50"
        "$mainMod CONTROL,k,resizeactive,0 -50"
        "$mainMod CONTROL,l,resizeactive,50 0"
        "$mainMod,1,workspace,1"
        "$mainMod,2,workspace,2"
        "$mainMod,3,workspace,3"
        "$mainMod,4,workspace,4"
        "$mainMod,5,workspace,5"
        "$mainMod,6,workspace,6"
        "$mainMod,7,workspace,7"
        "$mainMod,8,workspace,8"
        "$mainMod SHIFT,1,movetoworkspace,1"
        "$mainMod SHIFT,2,movetoworkspace,2"
        "$mainMod SHIFT,3,movetoworkspace,3"
        "$mainMod SHIFT,4,movetoworkspace,4"
        "$mainMod SHIFT,5,movetoworkspace,5"
        "$mainMod SHIFT,6,movetoworkspace,6"
        "$mainMod SHIFT,7,movetoworkspace,7"
        "$mainMod SHIFT,8,movetoworkspace,8"
        "$mainMod,S,togglespecialworkspace,LLM"
        "$mainMod SHIFT,S,movetoworkspace,special:LLM"
        "$mainMod,D,togglespecialworkspace,Chat"
        "$mainMod SHIFT,D,movetoworkspace,special:Chat"
        "$mainMod,C,togglespecialworkspace,Media"
        "$mainMod SHIFT,C,movetoworkspace,special:Media"
        "$mainMod,V,togglespecialworkspace,Notes"
        "$mainMod SHIFT,V,movetoworkspace,special:Notes"
        "$mainMod,ESCAPE,exec,hyprlock"
      ];

      bindm = [
        "$mainMod,mouse:272,movewindow"
        "$mainMod,mouse:273,resizewindow"
      ];

      ### WINDOW / LAYER RULES ###
      # NOTE: new rules use `windowrule` (not windowrulev2)
      # NOTE: effects like float/center require `on`
      windowrule = [
        # Special workspaces (NO "silent" so it switches/focuses immediately)
        "match:title ^(WhatsApp Web)$, workspace special:Chat"
        "match:title ^(Mattermost)$, workspace special:Chat"
        "match:title ^(Messenger)$, workspace special:Chat"
        "match:title ^(Instagram)$, workspace special:Chat"
        "match:title ^(Telegram Web - Telegram)$, workspace special:Chat"

        "match:title .*Spotify.* , workspace special:Media"
        "match:title .*ChatGPT.* , workspace special:LLM"
        "match:title .*Gemini.* , workspace special:LLM"
        "match:title .*Claude.* , workspace special:LLM"
        "match:title .*Google Keep.* , workspace special:Notes"

        # Floating Rules
        "match:class ^(dev\\.me\\.calc)$, float on"
        "match:class ^(dev\\.me\\.calc)$, center on"
        "match:class ^(dev\\.me\\.calc)$, size 400 500"

        "match:class ^(dev\\.me\\.file)$, float on"
        "match:class ^(dev\\.me\\.file)$, center on"
        "match:class ^(dev\\.me\\.file)$, size 1000 600"

        "match:class ^(dev\\.me\\.audio)$, float on"
        "match:class ^(dev\\.me\\.audio)$, center on"
        "match:class ^(dev\\.me\\.audio)$, size 1300 500"

        "match:class ^(dev\\.me\\.wifi)$, float on"
        "match:class ^(dev\\.me\\.wifi)$, center on"
        "match:class ^(dev\\.me\\.wifi)$, size 600 800"

        "match:class ^(dev\\.me\\.bluetooth)$, float on"
        "match:class ^(dev\\.me\\.bluetooth)$, center on"
        "match:class ^(dev\\.me\\.bluetooth)$, size 600 800"
      ];

      # New syntax: match first
      layerrule = [
        "match:namespace launcher, dim_around on"
        "match:namespace vicinae, dim_around on"
      ];
    };
  };
}

