        return startOffset + (exitOffset - startOffset) * exitProgress;
      }
      if (mode === visualTargetMode) {
        const entryProgress = easeOutCubic(
          (transitionProgress - 0.14) / 0.86);
        return startOffset * (1 - entryProgress);
      }
      return startOffset;
    }

    function startContentTransition(sourceMode, targetMode) {
      if (sourceMode === targetMode)
        return;

      const capturedOpacities = {};
      const capturedOffsets = {};
      for (let index = 0; index < contentModes.length; index++) {
        const mode = contentModes[index];
        capturedOpacities[mode] = contentOpacity(mode);
        capturedOffsets[mode] = contentOffset(mode);
      }

      contentTransition.stop();
      visualSourceMode = sourceMode;
      visualTargetMode = targetMode;
      const heightDelta = modeHeight(targetMode) - modeHeight(sourceMode);
      transitionDirection = heightDelta > 0 ? 1 : heightDelta < 0 ? -1 : 0;
      if (capturedOpacities[targetMode] <= 0.001)
        capturedOffsets[targetMode] = -transitionDirection * 10;
      startOpacities = capturedOpacities;
      startOffsets = capturedOffsets;
      transitionProgress = 0;
      contentTransition.restart();
    }

    anchors.horizontalCenter: parent.horizontalCenter
    anchors.top: parent.top
    width: targetWidth
    height: targetHeight
    radius: 18
    color: "#181926"
    clip: true
    opacity: window.entered ? 1 : 0

    Behavior on width {
      NumberAnimation {
        duration: 360
        easing.type: Easing.OutCubic
      }
    }

    Behavior on height {
      NumberAnimation {
        duration: 360
        easing.type: Easing.OutCubic
      }
    }

    NumberAnimation {
      id: contentTransition
      target: centerMorph
      property: "transitionProgress"
      from: 0
      to: 1
      duration: 360
      easing.type: Easing.Linear
    }

    Connections {
      target: window.statusData

      function onCenterTransitionSerialChanged() {
        const sourceMode = centerMorph.localTransitionMode(
          window.statusData.centerTransitionSourceMode,
          window.statusData.centerTransitionSourceMonitor);
        const targetMode = centerMorph.localTransitionMode(
          window.statusData.centerTransitionTargetMode,
          window.statusData.centerTransitionTargetMonitor);
        centerMorph.startContentTransition(sourceMode, targetMode);
      }
    }

    transform: Translate {
      y: window.entered ? 0 : -12
      Behavior on y {
        NumberAnimation {
          duration: 420
          easing.type: Easing.OutCubic
        }
      }
    }

    Behavior on opacity { NumberAnimation { duration: 220 } }

    WorkspaceSwitcher {
      id: workspaceSwitcher
      anchors {
        top: parent.top
        left: parent.left
        right: parent.right
      }
      height: implicitHeight
      transform: Translate { y: centerMorph.contentOffset("workspaces") }
      backgroundColor: "transparent"
      monitorName: window.monitorName
      opacity: centerMorph.contentOpacity("workspaces")
      enabled: !centerMorph.overlayVisible
    }

    VolumeIndicator {
      id: volumeIndicator
      anchors {
        top: parent.top
        left: parent.left
        right: parent.right
      }
      height: implicitHeight
      transform: Translate { y: centerMorph.contentOffset("volume") }
      statusData: window.statusData
      targetMonitor: window.monitorName
      color: "transparent"
      opacity: centerMorph.contentOpacity("volume")
      enabled: window.volumeOverlayActive
    }

    BrightnessIndicator {
      id: brightnessIndicator
      anchors {
        top: parent.top
        left: parent.left
        right: parent.right
      }
      height: implicitHeight
      transform: Translate { y: centerMorph.contentOffset("brightness") }
      statusData: window.statusData
      targetMonitor: window.monitorName
      color: "transparent"
      opacity: centerMorph.contentOpacity("brightness")
      enabled: window.brightnessOverlayActive
    }

    NowPlayingIndicator {
      id: nowPlayingIndicator
      anchors {
        top: parent.top
        left: parent.left
        right: parent.right
      }
      height: implicitHeight
      transform: Translate { y: centerMorph.contentOffset("media") }
      statusData: window.statusData
      opacity: centerMorph.contentOpacity("media")
      enabled: window.mediaOverlayActive
    }

    WifiSelector {
      id: wifiSelector
      anchors {
        top: parent.top
        left: parent.left
        right: parent.right
      }
      height: implicitHeight
      transform: Translate { y: centerMorph.contentOffset("wifi") }
      statusData: window.statusData
      opacity: centerMorph.contentOpacity("wifi")
      enabled: window.wifiSelectorKeyboardActive
    }

    BluetoothSelector {
      id: bluetoothSelector
      anchors {
        top: parent.top
        left: parent.left
        right: parent.right
      }
      height: implicitHeight
      transform: Translate { y: centerMorph.contentOffset("bluetooth") }
      statusData: window.statusData
      opacity: centerMorph.contentOpacity("bluetooth")
      enabled: window.bluetoothSelectorKeyboardActive
    }

    AppLauncher {
      id: appLauncher
      anchors {
        top: parent.top
        left: parent.left
        right: parent.right
      }
      height: implicitHeight
      transform: Translate { y: centerMorph.contentOffset("launcher") }
      statusData: window.statusData
      opacity: centerMorph.contentOpacity("launcher")
      enabled: window.appLauncherKeyboardActive
    }

    ChromeTabsLauncher {
      id: chromeTabsLauncher
      anchors {
        top: parent.top
        left: parent.left
        right: parent.right
      }
      height: implicitHeight
      transform: Translate { y: centerMorph.contentOffset("tabs") }
      statusData: window.statusData
      opacity: centerMorph.contentOpacity("tabs")
      enabled: window.chromeTabsKeyboardActive
    }

    UpdateSelector {
      id: updateSelector
      anchors {
        top: parent.top
        left: parent.left
        right: parent.right
      }
      height: implicitHeight
      transform: Translate { y: centerMorph.contentOffset("updates") }
      statusData: window.statusData
      opacity: centerMorph.contentOpacity("updates")
      enabled: window.updateSelectorKeyboardActive
    }

    ShaderEffect {
      id: activityBorder
      anchors.fill: parent
      visible: centerMorph.overlayVisible
      z: 100

      property size itemSize: Qt.size(width, height)
      property real phase: 0
      fragmentShader: Qt.resolvedUrl(
        "shaders/activity-border.frag.qsb")

      NumberAnimation on phase {
        from: 0
        to: 1
        duration: 1600
        loops: Animation.Infinite
        running: activityBorder.visible
      }
    }
  }

  Row {
    id: rightModules
    anchors.right: parent.right
    y: 0
    spacing: 10
    opacity: window.entered ? 1 : 0
    transform: Translate {
      y: window.entered ? 0 : -10
      Behavior on y {
        NumberAnimation {
          duration: 420
          easing.type: Easing.OutCubic
        }
      }
    }
    Behavior on opacity { NumberAnimation { duration: 240 } }

    Pill {
      visible: statusData.batteryAvailable
      text: statusData.batteryIcon() + " " + statusData.batteryPercent + "%"
      accent: "#f4dbd6"
    }

    Pill {
      text: statusData.audioMuted
        ? "󰖁"
        : statusData.audioIcon() + " " + statusData.audioVolume + "%"
      accent: "#b7bdf8"
      leftCommand: "pgrep -x pulsemixer >/dev/null 2>&1 || ghostty --class=dev.me.audio --title=Audio -e pulsemixer"
      interactive: true
      onWheelUp: {
        statusData.setVolume(0.02);
        statusData.showVolumeOverlay(window.monitorName);
      }
      onWheelDown: {
        statusData.setVolume(-0.02);
        statusData.showVolumeOverlay(window.monitorName);
      }
    }

    Pill {
      text: statusData.brightnessIcon() + " " + statusData.brightness + "%"
      accent: "#eed49f"
      wheelUpCommand: "brightnessctl set +5%"
      wheelDownCommand: "brightnessctl set 5%-"
      onWheelUp: statusData.showBrightnessOverlay(window.monitorName)
      onWheelDown: statusData.showBrightnessOverlay(window.monitorName)
    }

    Pill {
      text: statusData.weatherText
      accent: "#f5bde6"
      tooltipText: statusData.weatherTooltip
      tooltipHost: window
    }

    Pill {
      text: " " + statusData.dateText
      accent: "#8bd5ca"
    }

    Pill {
      text: " " + statusData.timeText
      accent: "#ed8796"
    }
  }

  PopupWindow {
    id: tooltip

    anchor.window: window
    anchor.rect.x: {
      if (window.tooltipAnchor === null)
        return 0;
      const point = window.tooltipAnchor.mapToItem(window.contentItem, 0, 0);
      return Math.max(0, Math.min(window.width - width,
        point.x + window.tooltipAnchor.width / 2 - width / 2));
    }
    anchor.rect.y: 42

    implicitWidth: Math.min(620, Math.max(120, window.tooltipText.length * 7 + 24))
    implicitHeight: tooltipLabel.implicitHeight + 20
    visible: window.tooltipVisible
    color: "transparent"

    Rectangle {
      anchors.fill: parent
      radius: 14
      color: "#363a4f"

      Text {
        id: tooltipLabel
        anchors.left: parent.left
        anchors.right: parent.right
        anchors.top: parent.top
        anchors.margins: 10
        text: window.tooltipText
        color: "#cad3f5"
        font.family: "Ubuntu Nerd Font"
        font.pixelSize: 14
        font.bold: true
        textFormat: Text.PlainText
        wrapMode: Text.Wrap
      }
    }
  }
}

text:
import QtQuick

FocusScope {
  id: root

  required property var statusData
  readonly property var results: statusData.chromeTabResults
  implicitWidth: 480
  implicitHeight: 398

  function syncSearchText() {
    if (searchInput.text !== statusData.chromeTabsQuery) {
      searchInput.text = statusData.chromeTabsQuery;
      searchInput.cursorPosition = searchInput.text.length;
    }
  }

  function revealSelection() {
    if (statusData.chromeTabsSelectedIndex >= 0 && results.length > 0)
      tabList.positionViewAtIndex(statusData.chromeTabsSelectedIndex,
        ListView.Contain);
  }

  function urlLabel(value) {
    const url = (value || "").toString();
    if (url === "")
      return "No URL";
    const match = url.match(/^[a-z]+:\/\/(?:www\.)?([^/]+)(.*)$/i);
    if (match === null)
      return url;
    return match[1] + (match[2] === "/" ? "" : match[2]);
  }

  onEnabledChanged: {
    if (enabled) {
      syncSearchText();
      Qt.callLater(() => {
        searchInput.forceActiveFocus();
        revealSelection();
      });
    }
  }

  Connections {
    target: statusData

    function onChromeTabsQueryChanged() {
      root.syncSearchText();
    }

    function onChromeTabResultsChanged() {
      Qt.callLater(() => root.revealSelection());
    }

    function onChromeTabsSelectedIndexChanged() {
      root.revealSelection();
    }
  }

  Item {
    anchors.fill: parent

    Text {
      id: searchIcon
      anchors.left: parent.left
      anchors.leftMargin: 16
      y: 9
      width: 22
      height: 24
      horizontalAlignment: Text.AlignHCenter
      verticalAlignment: Text.AlignVCenter
      text: "󰍉"
      color: "#ff33cc"
      font.family: "Ubuntu Nerd Font"
      font.pixelSize: 17
      font.bold: true
    }

    TextInput {
      id: searchInput
      anchors.left: searchIcon.right
      anchors.leftMargin: 10
      anchors.right: resultCount.left
      anchors.rightMargin: 12
      y: 7
      height: 28
      verticalAlignment: TextInput.AlignVCenter
      color: "#cad3f5"
      selectionColor: "#ff33cc"
      selectedTextColor: "#181926"
      clip: true
      font.family: "Ubuntu Nerd Font"
      font.pixelSize: 14
      font.bold: true
      cursorVisible: activeFocus

      onTextEdited: statusData.setChromeTabsQuery(text)

      Keys.onPressed: event => {
        const control = event.modifiers & Qt.ControlModifier;
        if (event.key === Qt.Key_Down || (control && event.key === Qt.Key_N)
            || event.key === Qt.Key_Tab) {
          statusData.moveChromeTabsSelection(1);
          event.accepted = true;
        } else if (event.key === Qt.Key_Up || (control && event.key === Qt.Key_P)
            || event.key === Qt.Key_Backtab) {
          statusData.moveChromeTabsSelection(-1);
          event.accepted = true;
        } else if (event.key === Qt.Key_PageDown) {
          statusData.moveChromeTabsSelection(8);
          event.accepted = true;
        } else if (event.key === Qt.Key_PageUp) {
          statusData.moveChromeTabsSelection(-8);
          event.accepted = true;
        } else if (event.key === Qt.Key_Home && control) {
          statusData.chromeTabsSelectedIndex = 0;
          event.accepted = true;
        } else if (event.key === Qt.Key_End && control
            && results.length > 0) {
          statusData.chromeTabsSelectedIndex = results.length - 1;
          event.accepted = true;
        } else if (event.key === Qt.Key_W && control) {
          statusData.closeSelectedChromeTab();
          event.accepted = true;
        } else if (event.key === Qt.Key_R && control) {
          statusData.requestChromeTabs();
          event.accepted = true;
        } else if (event.key === Qt.Key_Return || event.key === Qt.Key_Enter) {
          statusData.activateSelectedChromeTab();
          event.accepted = true;
        } else if (event.key === Qt.Key_Escape) {
          statusData.hideChromeTabs();
          event.accepted = true;
        }
      }
    }

    Text {
      anchors.left: searchInput.left
      anchors.right: searchInput.right
      y: searchInput.y
      height: searchInput.height
      visible: searchInput.text === ""
      verticalAlignment: Text.AlignVCenter
      text: "Search Chrome tabs…"
      color: "#6e738d"
      font.family: "Ubuntu Nerd Font"
      font.pixelSize: 14
      font.bold: true
    }

    Text {
      id: resultCount
      anchors.right: parent.right
      anchors.rightMargin: 16
      y: 9
      width: 88
      height: 24
      horizontalAlignment: Text.AlignRight
      verticalAlignment: Text.AlignVCenter
      text: statusData.chromeTabsLoading ? "LOADING"
        : results.length + (results.length === 1 ? " TAB" : " TABS")
      color: statusData.chromeTabsMessage !== "" ? "#ed8796" : "#a6da95"
      font.family: "Ubuntu Nerd Font"
      font.pixelSize: 10
      font.bold: true
    }

    Rectangle {
      anchors.left: parent.left
      anchors.right: parent.right
      anchors.leftMargin: 14
      anchors.rightMargin: 14
      y: 41
      height: 1
      color: "#363a4f"
    }

    ListView {
      id: tabList
      anchors.left: parent.left
      anchors.right: parent.right
      y: 48
      height: 342
      clip: true
      model: root.results
      currentIndex: statusData.chromeTabsSelectedIndex
      boundsBehavior: Flickable.StopAtBounds
      highlightMoveDuration: 120
      highlightResizeDuration: 120

      delegate: Item {
        id: tabRow
        required property var modelData
        required property int index
        readonly property var tab: modelData.tab
        readonly property bool selected: index === statusData.chromeTabsSelectedIndex

        width: tabList.width
        height: 42

        Rectangle {
          anchors.fill: parent
          anchors.leftMargin: 8
          anchors.rightMargin: 8
          anchors.topMargin: 2
          anchors.bottomMargin: 2
          radius: 10
          color: tabRow.selected ? "#363a4f" : "transparent"

          Behavior on color { ColorAnimation { duration: 90 } }
        }

        Rectangle {
          id: iconFrame
          anchors.left: parent.left
          anchors.leftMargin: 16
          anchors.verticalCenter: parent.verticalCenter
          width: 30
          height: 30
          radius: 8
          color: tabRow.selected ? "#494d64" : "#24273a"

          Text {
            anchors.centerIn: parent
            text: ""
            color: tabRow.tab.active ? "#a6da95" : "#8aadf4"
            font.family: "Ubuntu Nerd Font"
            font.pixelSize: 17
            font.bold: true
          }
        }

        Text {
          anchors.left: iconFrame.right
          anchors.leftMargin: 11
          anchors.right: stateIcons.left
          anchors.rightMargin: 10
          y: 4
          height: 18
          verticalAlignment: Text.AlignVCenter
          text: tabRow.tab.title || "Untitled tab"
          color: tabRow.selected ? "#ffffff" : "#cad3f5"
          elide: Text.ElideRight
          font.family: "Ubuntu Nerd Font"
          font.pixelSize: 13
          font.bold: true
        }

        Text {
          anchors.left: iconFrame.right
          anchors.leftMargin: 11
          anchors.right: stateIcons.left
          anchors.rightMargin: 10
          y: 21
          height: 15
          verticalAlignment: Text.AlignVCenter
          text: root.urlLabel(tabRow.tab.url)
          color: "#939ab7"
          elide: Text.ElideRight
          font.family: "Ubuntu Nerd Font"
          font.pixelSize: 10
          font.bold: true
        }

        Row {
          id: stateIcons
          anchors.right: launchHint.left
          anchors.rightMargin: 6
          anchors.verticalCenter: parent.verticalCenter
          spacing: 6

          Text {
            visible: tabRow.tab.pinned
            text: "󰐃"
            color: "#f5a97f"
            font.family: "Ubuntu Nerd Font"
            font.pixelSize: 12
            font.bold: true
          }

          Rectangle {
            visible: tabRow.tab.active
            anchors.verticalCenter: parent.verticalCenter
            width: 7
            height: 7
            radius: 3.5
            color: "#a6da95"
          }
        }

        Text {
          id: launchHint
          anchors.right: parent.right
          anchors.rightMargin: 18
          anchors.verticalCenter: parent.verticalCenter
          width: 24
          horizontalAlignment: Text.AlignHCenter
          text: tabRow.selected ? "󰌑" : ""
          color: "#ff33cc"
          font.family: "Ubuntu Nerd Font"
          font.pixelSize: 14
          font.bold: true
        }

        MouseArea {
          anchors.fill: parent
          acceptedButtons: Qt.LeftButton | Qt.RightButton
          cursorShape: Qt.PointingHandCursor
          onClicked: mouse => {
            if (mouse.button === Qt.RightButton)
              statusData.closeSelectedChromeTab(tabRow.index);
            else
              statusData.activateSelectedChromeTab(tabRow.index);
          }
        }
      }

      WheelHandler {
        acceptedDevices: PointerDevice.Mouse | PointerDevice.TouchPad
        onWheel: event => {
          if (event.angleDelta.y < 0)
            statusData.moveChromeTabsSelection(1);
          else if (event.angleDelta.y > 0)
            statusData.moveChromeTabsSelection(-1);
        }
      }
    }

    Text {
      visible: results.length === 0
      anchors.left: parent.left
      anchors.right: parent.right
      y: 165
      height: 58
      horizontalAlignment: Text.AlignHCenter
      verticalAlignment: Text.AlignVCenter
      text: statusData.chromeTabsLoading ? "Loading Chrome tabs…"
        : statusData.chromeTabsMessage !== ""
          ? statusData.chromeTabsMessage
          : statusData.chromeTabCatalog.length === 0
            ? "No Chrome tabs found"
            : "No matching Chrome tabs"
      color: statusData.chromeTabsMessage !== "" ? "#ed8796" : "#939ab7"
      font.family: "Ubuntu Nerd Font"
      font.pixelSize: 13
      font.bold: true
      wrapMode: Text.Wrap
    }
  }
}

